class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        seen = {}
        count = 0
        for c in word:
            if c.islower():
                if c in seen and seen[c].lower() != c:
                    count += 1
                seen[c] = c
            elif c.isupper():
                if c.lower() in seen and seen[c.lower()] != c.lower():
                    count += 1
        return count
